// Conservative merge (collapse): fold fine leaves into a parent.
// The invariant is that integrated quantities are preserved:
//   parent.vol = sum(child.vol)
//   parent.vol * parent.q[v] = sum(child.vol * child.q[v])
void fold_q(const CellPatch *a, int n, CellPatch *out) {
    if (!a || !out) return;
    if (n < 1) {
        memset(out, 0, sizeof(*out));
        return;
    }

    double vtot = 0.0;
    double mass[NVAR];
    for (int v = 0; v < NVAR; v++) mass[v] = 0.0;

    for (int i = 0; i < n && i < MAX_LEAVES; i++) {
        double vol = a->vol[i];
        if (vol <= 0.0) continue;
        vtot += vol;
        for (int v = 0; v < NVAR; v++) {
            mass[v] += vol * a->q[i * NVAR + v];
        }
    }

    memset(out, 0, sizeof(*out));
    out->n = 1;
    out->vol[0] = vtot;
    for (int v = 0; v < NVAR; v++) {
        out->q[v] = (vtot > 0.0) ? (mass[v] / vtot) : 0.0;
    }
}

// A simple ghost-band sampler used by the audit (not a conservation-critical operation).
