        ep.subfaces = k;
        for (int j = 0; j < k; j++) {
            const CellView *cell = &st->grid.cells[start + j];
            for (int v = 0; v < NVAR; v++) {
                ep.flux_vals[j * NVAR + v] =
                    REFLUX_RATE * cell->vol * (qbar[v] - cell->q[v]);
            }
        }
        op_m(&ep, &st->bank);
    }
}
